"""Application that uses the cache."""
from cache import CacheManager


def create_app(cache_ttl=60, cache_max=100):
    """Create an app instance with a configured cache."""
    cache = CacheManager(default_ttl=cache_ttl, max_size=cache_max)

    def get_user(user_id: int):
        key = f'user:{user_id}'
        cached = cache.get(key)
        if cached is not None:
            return cached
        # Simulate DB lookup
        user = {'id': user_id, 'name': f'User {user_id}', 'email': f'user{user_id}@example.com'}
        cache.set(key, user)
        return user

    def invalidate_user(user_id: int):
        return cache.delete(f'user:{user_id}')

    def cache_stats():
        return cache.stats()

    return {
        'cache': cache,
        'get_user': get_user,
        'invalidate_user': invalidate_user,
        'cache_stats': cache_stats,
    }

